import { Component, signal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute, Router } from '@angular/router';
import { FilingStatus } from '../../../core/models';

interface StatusOption {
  value: FilingStatus;
  label: string;
  hint: string;
}

/** Wizard step 1 — choose filing status, then advance to dependents. */
@Component({
  selector: 'app-filing-status',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './filing-status.component.html',
  styleUrl: './filing-status.component.css',
})
export class FilingStatusComponent {
  returnId = '';
  saving = signal<boolean>(false);

  selected = signal<FilingStatus>('single');

  readonly options: StatusOption[] = [
    { value: 'single', label: 'Single', hint: 'Unmarried or legally separated' },
    { value: 'married_joint', label: 'Married filing jointly', hint: 'Combine income with your spouse' },
    { value: 'married_separate', label: 'Married filing separately', hint: 'File apart from your spouse' },
    { value: 'head_of_household', label: 'Head of household', hint: 'Unmarried and supporting a dependent' },
  ];

  constructor(private route: ActivatedRoute, private router: Router) {
    this.returnId = this.route.parent?.snapshot.paramMap.get('id') ?? '';
  }

  choose(value: FilingStatus): void {
    this.selected.set(value);
  }

  next(): void {
    // Mockup: service_agent will POST the status + PATCH /step here.
    this.saving.set(true);
    this.router.navigate(['/returns', this.returnId, 'wizard', 'dependents']);
  }
}
